   183→        }
   184→      }
   185→
   186→      case 'report': {
   187→        await api('POST', '/api/messages', {
   188→          from: AGENT_ID,
   189→          missionId: MISSION_ID,
   190→          type: 'report',
   191→          summary: a.summary,
   192→          artifacts: a.artifacts ?? [],
   193→        })
   194→        return {
   195→          content: [{ type: 'text', text: `Report submitted. Mission ${MISSION_ID} marked complete.` }],
   196→        }
   197→      }
   198→
   199→      case 'memory_read': {
   200→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
   201→        const content = await readFile(memPath, 'utf-8').catch(() => '(empty)')
   202→        return { content: [{ type: 'text', text: content }] }
   203→      }
   204→
   205→      case 'memory_write': {
   206→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
   207→        const existing = await readFile(memPath, 'utf-8').catch(() => '')
   208→        const timestamp = new Date().toISOString()
