   257→          `[${m.channel}] [${m.ts}] ${m.from}: ${m.text}`
   258→        ).join('\n')
   259→        return { content: [{ type: 'text', text: `${unread.length} unread message(s):\n${formatted}` }] }
   260→      }
   261→
   262→      case 'cross_team_delegate': {
   263→        // Check caller's rank — only director+ can cross-team delegate
