   287→          return {
   288→            content: [{ type: 'text', text: `Error: Team "${a.to_team}" not found or has no head.` }],
   289→            isError: true,
   290→          }
   291→        }
   292→
   293→        // Create a cross-team message
   294→        await api('POST', '/api/messages', {
   295→          from: AGENT_ID,
   296→          missionId: MISSION_ID,
   297→          type: 'escalate',
   298→          question: `[Cross-team from ${callerProfile.team ?? 'unknown'}] Task: ${a.task}\n\nWhy: ${a.why}\nKnown: ${a.known ?? 'N/A'}\nExpected output: ${a.expected_output}`,
   299→          context: `Cross-team delegation to ${a.to_team}`,
   300→          to: targetHead,
   301→        })
   302→
   303→        // Delegate the task to the target head
   304→        const result = await api('POST', '/api/delegate', {
   305→          fromAgentId: AGENT_ID,
   306→          toAgentId: targetHead,
   307→          missionId: MISSION_ID,
   308→          task: `[Cross-team request from ${callerProfile.title ?? AGENT_ID}]\n\nTask: ${a.task}\nWhy: ${a.why}\nKnown context: ${a.known ?? 'N/A'}\nExpected output: ${a.expected_output}`,
   309→        })
   310→
   311→        return {
   312→          content: [{ type: 'text', text: `Cross-team task delegated to ${targetHead} (${a.to_team}). Sub-mission: ${result.subMissionId}` }],
   313→        }
   314→      }
   315→
   316→      default:
   317→        return { content: [{ type: 'text', text: `Unknown tool: ${name}` }], isError: true }
   318→    }
   319→  } catch (err) {
   320→    return {
   321→      content: [{ type: 'text', text: `Tool error: ${(err as Error).message}` }],
   322→      isError: true,
   323→    }
   324→  }
   325→})
   326→
   327→const transport = new StdioServerTransport()
