     1→import { broadcast } from './hub'
     2→import { readFile, writeFile, mkdir } from 'fs/promises'
     3→import { join } from 'path'
     4→import { existsSync } from 'fs'
     5→
     6→const AGENTS_DIR = join(import.meta.dir, '../../../agents')
     7→const MISSIONS_DIR = join(import.meta.dir, '../../../missions')
     8→const MCP_SERVER_PATH = join(import.meta.dir, '../mcp/server.ts')
     9→
    10→const running = new Map<string, ReturnType<typeof Bun.spawn>>()
    11→
    12→export function isRunning(agentId: string) {
    13→  return running.has(agentId)
    14→}
    15→
    16→export function getRunningAgents(): string[] {
    17→  return Array.from(running.keys())
    18→}
    19→
    20→export interface RunOptions {
    21→  workspace?: string
    22→  sessionId?: string
    23→  resume?: boolean
    24→}
    25→
    26→export async function runAgent(
    27→  agentId: string,
    28→  missionId: string,
    29→  prompt: string,
    30→  options: RunOptions = {}
    31→) {
    32→  if (running.has(agentId)) {
    33→    throw new Error(`Agent ${agentId} is already running`)
    34→  }
    35→
    36→  const profilePath = join(AGENTS_DIR, agentId, 'profile.json')
    37→  const profile = JSON.parse(await readFile(profilePath, 'utf-8'))
    38→
    39→  // Resolve workspace
    40→  let workspace = options.workspace
    41→  if (!workspace) {
    42→    try {
    43→      const statePath = join(MISSIONS_DIR, missionId, 'state.json')
    44→      const state = JSON.parse(await readFile(statePath, 'utf-8'))
    45→      workspace = state.workspace
    46→    } catch {}
    47→  }
    48→  if (!workspace && profile.default_workspace) {
    49→    workspace = profile.default_workspace.replace('~', process.env.HOME ?? '')
    50→  }
    51→  const cwd = workspace ?? process.cwd()
    52→
    53→  // Inject MCP config into workspace
    54→  await injectMcpConfig(cwd, agentId, missionId)
    55→
    56→  const driver = profile.driver
    57→  const systemPrompt = driver.system_prompt ?? ''
    58→
    59→  // Build full prompt = system prompt + task + artifacts dir
    60→  const artifactsDir = join(MISSIONS_DIR, missionId, 'artifacts')
    61→  await mkdir(artifactsDir, { recursive: true })
    62→
    63→  const fullPrompt = systemPrompt
    64→    ? `${systemPrompt}\n\n---\nMission ID: ${missionId}\nArtifacts directory: ${artifactsDir}\nSave ALL output files to the artifacts directory above.\nTask: ${prompt}`
    65→    : `Mission ID: ${missionId}\nArtifacts directory: ${artifactsDir}\nSave ALL output files to the artifacts directory above.\nTask: ${prompt}`
    66→
    67→  // Check for unread messages and append hint
    68→  let finalPrompt = fullPrompt
    69→  try {
    70→    const res = await fetch(`http://localhost:3001/api/channels/unread/${agentId}`)
    71→    const unread = await res.json()
    72→    if (Array.isArray(unread) && unread.length > 0) {
    73→      finalPrompt += `\n\nYou have ${unread.length} unread message(s). Use read_messages() to check them before starting work.`
    74→    }
    75→  } catch {}
    76→
    77→  broadcast('agent:start', { agentId, missionId, workspace: cwd })
    78→
    79→  let cmd: string[]
    80→
    81→  if (driver.type === 'claude-code') {
    82→    // Build args, replacing {{full_prompt}} placeholder
    83→    const args = (driver.args as string[]).map((a: string) =>
    84→      a.replace('{{full_prompt}}', finalPrompt).replace('{{prompt}}', prompt)
    85→    )
    86→
    87→    // Inject session flags
    88→    if (options.sessionId) {
    89→      const insertAt = args.indexOf('-p')
    90→      if (insertAt !== -1) args.splice(insertAt, 0, '--resume', options.sessionId)
    91→    } else if (options.resume) {
    92→      const insertAt = args.indexOf('-p')
    93→      if (insertAt !== -1) args.splice(insertAt, 0, '--continue')
    94→    }
    95→
    96→    cmd = [driver.command, ...args]
    97→  } else if (driver.type === 'cli') {
    98→    // Legacy opencode-style
    99→    const args = (driver.args as string[]).map((a: string) =>
   100→      a.replace('{{prompt}}', finalPrompt)
   101→    )
   102→    if (driver.command === 'opencode' && (options.sessionId || options.resume)) {
   103→      const sessionFlags = options.sessionId ? ['-s', options.sessionId] : ['-c']
   104→      const [sub, ...rest] = args
   105→      cmd = [driver.command, sub, ...sessionFlags, ...rest]
   106→    } else {
   107→      cmd = [driver.command, ...args]
   108→    }
   109→  } else {
   110→    cmd = ['claude', '--dangerously-skip-permissions', '-p', finalPrompt]
   111→  }
   112→
   113→  const proc = Bun.spawn(cmd, {
   114→    cwd,
   115→    stdout: 'pipe',
   116→    stderr: 'pipe',
   117→    env: (() => {
   118→      const env = { ...process.env }
   119→      // Normalize: ANTHROPIC_AUTH_TOKEN (zshrc style) → ANTHROPIC_API_KEY (claude CLI expects)
   120→      env.ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY ?? process.env.ANTHROPIC_AUTH_TOKEN ?? ''
   121→      // Remove nested Claude Code session marker so agents can spawn claude
   122→      delete env.CLAUDECODE
   123→      delete env.CLAUDE_CODE_ENTRYPOINT
   124→      return env
   125→    })()
   126→  })
   127→
   128→  running.set(agentId, proc)
   129→
   130→  // Stream stdout
   131→  ;(async () => {
   132→    const decoder = new TextDecoder()
   133→    const reader = proc.stdout.getReader()
   134→    try {
   135→      while (true) {
   136→        const { done, value } = await reader.read()
   137→        if (done) break
   138→        broadcast('agent:output', { agentId, missionId, text: decoder.decode(value) })
   139→      }
   140→    } finally { reader.releaseLock() }
   141→  })()
   142→
   143→  // Stream stderr
   144→  ;(async () => {
   145→    const decoder = new TextDecoder()
   146→    const reader = proc.stderr.getReader()
   147→    try {
   148→      while (true) {
   149→        const { done, value } = await reader.read()
   150→        if (done) break
   151→        broadcast('agent:error', { agentId, missionId, text: decoder.decode(value) })
   152→      }
   153→    } finally { reader.releaseLock() }
   154→  })()
   155→
   156→  proc.exited.then(async (code) => {
   157→    running.delete(agentId)
   158→
   159→    // Capture opencode session ID
   160→    let sessionId: string | undefined
   161→    if (driver.command === 'opencode') {
   162→      sessionId = await getLatestOpenCodeSession(cwd)
   163→    }
   164→
   165→    // Persist session ID
   166→    if (sessionId) {
   167→      try {
   168→        const statePath = join(MISSIONS_DIR, missionId, 'state.json')
   169→        const state = JSON.parse(await readFile(statePath, 'utf-8'))
   170→        state.sessions = state.sessions ?? {}
   171→        state.sessions[agentId] = sessionId
   172→        await writeFile(statePath, JSON.stringify(state, null, 2))
   173→      } catch {}
   174→    }
   175→
   176→    broadcast('agent:done', { agentId, missionId, exitCode: code, sessionId })
   177→  })
   178→}
