   180→async function injectMcpConfig(cwd: string, agentId: string, missionId: string) {
   181→  try {
   182→    const claudeDir = join(cwd, '.claude')
   183→    await mkdir(claudeDir, { recursive: true })
   184→    const config = {
   185→      mcpServers: {
   186→        clawcorp: {
   187→          command: 'bun',
   188→          args: ['run', MCP_SERVER_PATH],
   189→          env: {
   190→            CLAWCORP_SERVER: 'http://localhost:3001',
   191→            CLAWCORP_AGENT_ID: agentId,
   192→            CLAWCORP_MISSION_ID: missionId,
