   139→server.setRequestHandler(CallToolRequestSchema, async (request) => {
   140→  const { name, arguments: args } = request.params
   141→  const a = (args ?? {}) as Record<string, unknown>
   142→
   143→  try {
   144→    switch (name) {
   145→      case 'escalate': {
   146→        // Create escalation message
   147→        const msg = await api('POST', '/api/messages', {
   148→          from: AGENT_ID,
   149→          missionId: MISSION_ID,
   150→          type: 'escalate',
   151→          question: a.question,
   152→          context: a.context ?? '',
   153→        })
   154→
   155→        // Poll for answer (max 10 minutes)
   156→        const maxWait = 10 * 60 * 1000
   157→        const interval = 4000
   158→        const start = Date.now()
   159→
   160→        while (Date.now() - start < maxWait) {
   161→          await Bun.sleep(interval)
   162→          const updated = await api('GET', `/api/messages/${msg.id}`)
   163→          if (updated.status === 'answered') {
   164→            return { content: [{ type: 'text', text: `Supervisor answered: ${updated.answer}` }] }
   165→          }
   166→        }
   167→
   168→        return {
   169→          content: [{ type: 'text', text: 'No answer received in time. Make your best judgment and proceed.' }],
   170→        }
   171→      }
   172→
   173→      case 'delegate': {
   174→        const result = await api('POST', '/api/delegate', {
   175→          fromAgentId: AGENT_ID,
   176→          toAgentId: a.agent_id,
   177→          missionId: MISSION_ID,
   178→          task: a.task,
   179→          workspace: a.workspace,
   180→        })
   181→        return {
   182→          content: [{ type: 'text', text: `Delegated to ${a.agent_id}. Sub-mission: ${result.subMissionId}. Waiting for completion...` }],
   183→        }
   184→      }
   185→
   186→      case 'report': {
   187→        await api('POST', '/api/messages', {
   188→          from: AGENT_ID,
   189→          missionId: MISSION_ID,
   190→          type: 'report',
   191→          summary: a.summary,
   192→          artifacts: a.artifacts ?? [],
   193→        })
   194→        return {
   195→          content: [{ type: 'text', text: `Report submitted. Mission ${MISSION_ID} marked complete.` }],
   196→        }
   197→      }
   198→
   199→      case 'memory_read': {
   200→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
   201→        const content = await readFile(memPath, 'utf-8').catch(() => '(empty)')
   202→        return { content: [{ type: 'text', text: content }] }
   203→      }
   204→
   205→      case 'memory_write': {
   206→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
   207→        const existing = await readFile(memPath, 'utf-8').catch(() => '')
   208→        const timestamp = new Date().toISOString()
   209→        await writeFile(memPath, `${existing}\n\n## ${timestamp}\n${a.content}`)
   210→        return { content: [{ type: 'text', text: 'Memory saved.' }] }
   211→      }
   212→
   213→      case 'send_message': {
   214→        const result = await api('POST', '/api/channels/send', {
   215→          from: AGENT_ID,
   216→          to: a.to,
   217→          text: a.text,
   218→          replyTo: a.reply_to,
   219→        })
   220→        if (result.error) {
   221→          return { content: [{ type: 'text', text: `Error: ${result.error}` }], isError: true }
   222→        }
   223→        return { content: [{ type: 'text', text: `Message sent (${result.messageId})` }] }
   224→      }
   225→
   226→      case 'read_messages': {
   227→        const limit = (a.limit as number) ?? 20
   228→        const channel = a.channel as string | undefined
   229→
   230→        if (channel) {
   231→          // Read specific channel
   232→          let channelId: string
   233→          if (channel.startsWith('#')) {
   234→            channelId = channel.slice(1)
   235→          } else if (channel.startsWith('@')) {
   236→            const targetAgent = channel.slice(1)
   237→            channelId = `dm-${[AGENT_ID, targetAgent].sort().join('-')}`
   238→          } else {
   239→            channelId = channel
   240→          }
   241→          const messages = await api('GET', `/api/channels/${channelId}/messages?limit=${limit}`)
   242→          if (!Array.isArray(messages) || messages.length === 0) {
   243→            return { content: [{ type: 'text', text: 'No messages in this channel.' }] }
   244→          }
   245→          const formatted = messages.map((m: Record<string, string>) =>
   246→            `[${m.ts}] ${m.from}: ${m.text}${m.replyTo ? ` (reply to ${m.replyTo})` : ''}`
   247→          ).join('\n')
   248→          return { content: [{ type: 'text', text: formatted }] }
   249→        }
   250→
   251→        // No channel specified — get unread messages mentioning this agent
   252→        const unread = await api('GET', `/api/channels/unread/${AGENT_ID}`)
   253→        if (!Array.isArray(unread) || unread.length === 0) {
