## Auto-Dispatch Implementation Plan

### Architecture Summary

The flow is: **Chairman creates a task** -> **system calls LLM to pick the right executive** -> **creates a mission, spawns that executive** -> **executive cascades down using existing `delegate` MCP tool** -> **Chairman watches progress in Live Log**.

This is Option C + A from your recommendation. It requires exactly one new server-side module (`AutoDispatch.ts`), a small modification to the task routes, and a UI change to replace/supplement the "Run" button with "Dispatch".

---

### Step 1: Create `/Users/junjie/research/ClawCorp/server/src/lib/AutoDispatch.ts`

This is the core new file. It follows the exact same pattern as `SmartHire.ts`: uses the Anthropic SDK directly to make a routing decision, then calls existing infrastructure (`runAgent`) to execute.

```typescript
import Anthropic from '@anthropic-ai/sdk'
import { readdir, readFile, writeFile, mkdir } from 'fs/promises'
import { join } from 'path'
import { broadcast } from './hub'
import { runAgent } from './AgentRunner'

const AGENTS_DIR = join(import.meta.dir, '../../../agents')
const TEAMS_DIR = join(import.meta.dir, '../../../teams')
const MISSIONS_DIR = join(import.meta.dir, '../../../missions')

type AgentProfile = {
  id: string
  title: string
  department: string
  description: string
  rank: string
  team: string
  reports_to: string
  subordinates: string[]
  driver: {
    system_prompt: string
    [key: string]: unknown
  }
}

type RoutingDecision = {
  executive_id: string
  reasoning: string
  suggested_approach: string
}

export async function autoDispatch(
  taskId: string,
  taskTitle: string,
  workspace?: string
): Promise<{ missionId: string; executiveId: string; reasoning: string }> {
  const anthropic = new Anthropic()

  broadcast('dispatch:start', { taskId, title: taskTitle })

  // 1. Load all executive profiles (rank === 'executive')
  const executives = await loadExecutives()

  if (executives.length === 0) {
    throw new Error('No executives found in the organization')
  }

  // 2. Load team info for context
  const teams = await loadTeams()

  // 3. Ask LLM to route
  const decision = await routeTask(anthropic, taskTitle, executives, teams)

  broadcast('dispatch:routed', {
    taskId,
    executiveId: decision.executive_id,
    reasoning: decision.reasoning,
  })

  // 4. Create a mission from this task
  const missionId = `M-${Date.now()}`
  const missionDir = join(MISSIONS_DIR, missionId)
  await mkdir(join(missionDir, 'artifacts'), { recursive: true })

  const missionState = {
    id: missionId,
    title: taskTitle,
    type: 'engineering',
    status: 'in_progress',
    current_stage: 'development',
    assignee: decision.executive_id,
    workspace: workspace ?? null,
    sessions: {},
    created_at: new Date().toISOString(),
    dispatched_from_task: taskId,
    routing_reasoning: decision.reasoning,
    history: [
      {
        at: new Date().toISOString(),
        event: 'auto-dispatched',
        to: decision.executive_id,
        reasoning: decision.reasoning,
      },
    ],
  }

  await writeFile(
    join(missionDir, 'state.json'),
    JSON.stringify(missionState, null, 2)
  )

  // 5. Build the prompt that includes routing context
  const prompt = [
    `The Chairman has assigned this task to you via auto-dispatch.`,
    ``,
    `Task: ${taskTitle}`,
    ``,
    `Routing reasoning: ${decision.reasoning}`,
    decision.suggested_approach
      ? `Suggested approach: ${decision.suggested_approach}`
      : '',
    ``,
    `You are responsible for completing this task. You may:`,
    `- Do it yourself if it's within your expertise`,
    `- Use 'delegate' to assign sub-tasks to your subordinates`,
    `- Use 'delegate' multiple times to split work across several agents`,
    `- Use 'cross_team_delegate' if part of the work belongs to another department`,
    ``,
    `When all work is complete, use 'report' to summarize what was accomplished.`,
  ]
    .filter(Boolean)
    .join('\n')

  // 6. Spawn the executive agent
  broadcast('dispatch:spawning', {
    taskId,
    missionId,
    executiveId: decision.executive_id,
  })

  runAgent(decision.executive_id, missionId, prompt, { workspace }).catch(
    (err) => {
      broadcast('dispatch:error', {
        taskId,
        missionId,
        message: err.message,
      })
    }
  )

  broadcast('dispatch:running', {
    taskId,
    missionId,
    executiveId: decision.executive_id,
  })

  return {
    missionId,
    executiveId: decision.executive_id,
    reasoning: decision.reasoning,
  }
}

async function loadExecutives(): Promise<AgentProfile[]> {
  const dirs = await readdir(AGENTS_DIR, { withFileTypes: true })
  const profiles: AgentProfile[] = []

  for (const d of dirs) {
    if (!d.isDirectory()) continue
    try {
      const profilePath = join(AGENTS_DIR, d.name, 'profile.json')
      const profile: AgentProfile = JSON.parse(
        await readFile(profilePath, 'utf-8')
      )
      if (profile.rank === 'executive') {
        profiles.push(profile)
      }
    } catch {
      // skip unreadable profiles
    }
  }

  return profiles
}

async function loadTeams(): Promise<
  Array<{ id: string; name: string; head: string; members: string[] }>
> {
  try {
    const dirs = await readdir(TEAMS_DIR, { withFileTypes: true })
    const teams = []
    for (const d of dirs) {
      if (!d.isDirectory()) continue
      try {
        const teamPath = join(TEAMS_DIR, d.name, 'team.json')
        teams.push(JSON.parse(await readFile(teamPath, 'utf-8')))
      } catch {}
    }
    return teams
  } catch {
    return []
  }
}

async function routeTask(
  anthropic: Anthropic,
  taskTitle: string,
  executives: AgentProfile[],
  teams: Array<{ id: string; name: string; head: string; members: string[] }>
): Promise<RoutingDecision> {
  const executiveSummaries = executives
    .map(
      (e) =>
        `- ${e.id} (${e.title}): ${e.description}. ` +
        `Department: ${e.department}. ` +
        `Subordinates: ${e.subordinates.join(', ') || 'none'}. ` +
        `Team: ${e.team}`
    )
    .join('\n')

  const teamSummaries = teams
    .map(
      (t) =>
        `- ${t.name} (${t.id}): head=${t.head}, members=[${t.members.join(', ')}]`
    )
    .join('\n')

  const response = await anthropic.messages.create({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 512,
    messages: [
      {
        role: 'user',
        content: `You are the routing system for ClawCorp, an AI organization.

The Chairman has created a task. Decide which executive should handle it.

TASK: "${taskTitle}"

AVAILABLE EXECUTIVES:
${executiveSummaries}

TEAMS:
${teamSummaries}

RULES:
1. Pick exactly ONE executive to own this task.
2. If the task is about building software, coding, architecture, or technical implementation → product-manager (who oversees engineering via architect).
3. If the task is about research, literature review, experiments, analysis, or scientific investigation → principal-investigator.
4. If unclear, default to product-manager.
5. Consider the executive's subordinates — pick the one whose team can actually do the work.

Return ONLY a JSON object with:
- executive_id: the id of the chosen executive
- reasoning: one sentence explaining why
- suggested_approach: one sentence on how the executive should tackle it (delegate to whom, etc.)

No markdown fences, no explanation outside the JSON.`,
      },
    ],
  })

  const text =
    response.content[0].type === 'text' ? response.content[0].text : ''
  const jsonMatch = text.match(/\{[\s\S]*\}/)
  if (!jsonMatch) {
    // Fallback: default to product-manager
    return {
      executive_id: 'product-manager',
      reasoning: 'Failed to parse routing decision, defaulting to product-manager',
      suggested_approach: 'Assess the task and delegate appropriately',
    }
  }

  const decision: RoutingDecision = JSON.parse(jsonMatch[0])

  // Validate that the chosen executive actually exists
  const valid = executives.find((e) => e.id === decision.executive_id)
  if (!valid) {
    return {
      executive_id: executives[0].id,
      reasoning: `LLM chose "${decision.executive_id}" which does not exist. Defaulting to ${executives[0].id}.`,
      suggested_approach: decision.suggested_approach ?? '',
    }
  }

  return decision
}
```

Key design points:
- Follows `SmartHire.ts` pattern exactly: Anthropic SDK call, broadcast events, filesystem operations.
- The LLM prompt is deliberately simple and deterministic. It uses `claude-sonnet-4-20250514` (same as SmartHire) for speed and cost.
- Has a fallback: if LLM parsing fails or returns an invalid executive, it defaults to `product-manager`.
- The prompt given to the executive includes routing context so the agent understands WHY it was chosen and is encouraged to delegate further.
- Uses `max_tokens: 512` since the routing decision is tiny -- this keeps it fast (sub-2-second latency).

